  ('generalpolice-94737317-moex-00762', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '有關遺產分割之敘述，下列何者正確？', '["胎兒為繼承人時，雖其尚未出生，仍須保留其應繼分", "土地進行遺產分割前，各繼承人可自由處分其應有部分", "以遺囑禁止遺產分割15年者，該禁止遺產分割之遺囑無效", "遺產分割後，各繼承人對於他繼承人因分割而取得之債權，就遺產分割時，債務人之支付能力，不負擔 保責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00763', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '不當得利受領人於受領時不知無法律上之原因而受利益者，關於其應返還利益之範圍，下列敘述何者錯誤？', '["受領人僅負返還現存利益之責任", "受領人須返還受領時之原利益，並附加利息償還之，如有損害，亦應賠償", "受領人之利益原形雖不存在，但受領人所獲財產總額之增加仍存在者，負返還責任", "受領人受領之利益已不存在者，免負返還或償還價額之責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00764', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '甲上網向乙果農訂購葡萄5箱，約定送貨地點為甲之臺北住處，價金當即以信用卡支付完畢。葡萄送到後， 甲開箱發現有3箱葡萄已經發霉。甲原則上得向乙主張何種權利？', '["甲得向乙主張不當得利，請求返還3箱葡萄之價金", "甲得向乙主張侵權行為，請求返還3箱葡萄之價金", "甲得向乙主張給付不能，請求賠償相當於3箱葡萄價金之損害", "甲得向乙主張瑕疵擔保責任，請求乙另行交付3箱具約定品質的葡萄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00765', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '下列何者非屬單獨行為？', '["贈與契約", "物權之拋棄", "解除權之行使", "撤銷權之行使"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00766', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '甲向乙租A屋，雙方約定租期5年，租金每月3萬元，押金6萬元，但未訂立書面，下列敘述何者正確？', '["甲、乙間之租賃契約未以字據定之，故不生效力", "甲、乙間之租賃契約未以字據定之，故效力未定", "甲、乙間之租賃契約仍生效力，惟租期僅限於1年", "甲、乙間之租賃契約仍生效力，但視為不定期租賃"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00767', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '甲將其所有之汽車借給乙使用，不久卻將汽車贈與給乙，則甲對乙得以何種方式交付該汽車？', '["現實交付", "簡易交付", "占有改定", "指示交付"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00768', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '甲與友人乙謀議，要侵入丙家行搶。兩人依計劃，翻牆進入丙家庭院埋伏。丙開車返家時，甲持槍上前喝 阻，要丙下車，而乙在旁邊把風，丙見狀，踩油門加速衝撞甲。甲情急之下自行朝擋風玻璃射擊丙，丙頭 部中彈，經送加護病房搶救，所幸生還。關於本案，下列敘述何者正確？', '["乙不構成殺人未遂或重傷罪的共同正犯", "甲不能主張正當防衛，但可依緊急避難阻卻殺人未遂罪責", "甲開槍出於情急，並沒有殺丙的意圖，因此不具殺人故意", "丙開車衝撞行為，屬於防衛過當，但依情形可減輕或阻卻罪責"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00769', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '小明因病必須服用藥物史丁諾斯，某日服用後睡覺，因該藥物的副作用，產生夢遊，毆傷室友小華，該行 為不處罰的理由何者最適當？', '["無刑法期待可能性", "非刑法意義之行為", "具有阻卻違法事由", "具有被害人之承諾"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00770', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於易服社會勞動，下列敘述何者正確？', '["是一種保安處分", "是一種機構內處遇", "等於舊法中的易服勞役", "是短期自由刑的替代刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00771', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於刑法上責任能力之規定，下列敘述何者錯誤？', '["未滿14歲人之行為，不罰", "滿80歲人之行為，得減輕其刑", "瘖啞人之行為，得減輕其刑", "藉酒裝瘋之人，得主張其行為時因精神障礙或其他心智缺陷，致不能辨識其行為違法或欠缺依其辨識而 行為之能力者，不罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "6c9172a49c28", "answer_pdf_sha1": "b26325746d0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
